import hashlib
import sympy
from Crypto.Util.number import *

flag='BITs2CTF{isjna_cask_asdasfasqwe_dmqwo}'





half = int(len(flag) / 2)

flag1 = flag[:half]
flag2 = flag[half:]



e = 0x10001

flag1 = flag1.encode('utf-8')
flag2 = flag2.encode('utf-8')
F1 = bytes_to_long(flag1)
F2 = bytes_to_long(flag2)

c1 = F1 + F2
c2 = pow(F1, 3) + pow(F2, 3)
assert(c2 < N)

m1 = pow(c1, e, N)
m2 = pow(c2, e, N)

print(m1)       #
print(m2)       #